import{_ as e,o,c as a,S as i}from"./chunks/framework.058ce8a4.js";const p=JSON.parse('{"title":"UX specification: Blue dot and geolocation behavior","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ux-spec-blue-dot-and-geolocation-behavior.md","lastUpdated":1781613983000}'),n={name:"guide/ux-spec-blue-dot-and-geolocation-behavior.md"};function s(r,t,l,d,h,u){return o(),a("div",null,t[0]||(t[0]=[i('<h1 id="ux-specification-blue-dot-and-geolocation-behavior" tabindex="-1">UX specification: Blue dot and geolocation behavior <a class="header-anchor" href="#ux-specification-blue-dot-and-geolocation-behavior" aria-label="Permalink to &quot;UX specification: Blue dot and geolocation behavior&quot;">​</a></h1><h2 id="_1-initial-map-load-permissions" tabindex="-1">1. Initial map load &amp; permissions <a class="header-anchor" href="#_1-initial-map-load-permissions" aria-label="Permalink to &quot;1. Initial map load &amp; permissions&quot;">​</a></h2><p><strong>Expected behavior:</strong></p><ul><li><strong>Permission request:</strong> Upon opening the map, the system requests geolocation access via the browser.</li><li><strong>Initial viewport:</strong> Once permission is granted, the map automatically pans to the user’s current position (center-aligned).</li><li><strong>Zoom level:</strong> The system preserves the current zoom level. It does not automatically adjust the zoom to a predefined scale. <ul><li><em>Note:</em> If the user is far from the event location, the map will pan to their coordinates, but they may need to zoom in manually to see details.</li></ul></li><li><strong>Floor awareness:</strong> The Blue Dot is visible only when the user is on the currently active floor. If the user is on a different floor, the Blue Dot is hidden to reduce confusion.</li></ul><h2 id="_2-navigation-movement-logic" tabindex="-1">2. Navigation &amp; movement logic <a class="header-anchor" href="#_2-navigation-movement-logic" aria-label="Permalink to &quot;2. Navigation &amp; movement logic&quot;">​</a></h2><p><strong>Is there a navigation mode?</strong></p><p>Currently, ExpoFP uses a manual focus approach rather than a turn-by-turn navigation lock.</p><ul><li><strong>Auto-centering:</strong> The camera follows the user only on the first position update. After that, the map remains user-controlled. To re-center, the user must tap the <strong>Find location</strong> button.</li><li><strong>Map rotation:</strong> The map does not rotate automatically to match the user’s heading. It remains North-up (or at the default floor plan orientation).</li><li><strong>Blue Dot orientation:</strong> The Blue Dot rotates based on the device’s compass to indicate the user’s facing direction.</li></ul><h2 id="_3-wayfinding-route-snapping" tabindex="-1">3. Wayfinding &amp; route snapping <a class="header-anchor" href="#_3-wayfinding-route-snapping" aria-label="Permalink to &quot;3. Wayfinding &amp; route snapping&quot;">​</a></h2><p>When a route is active, the system applies smart snapping to improve stability and usability:</p><ul><li><strong>Snapping threshold:</strong> If the user is within 7.5 meters of the suggested route, the Blue Dot snaps to the route line. This reduces visible position shifts caused by GPS jitter.</li><li><strong>Route progress:</strong> As the user moves, the completed portion of the path changes color to grey, indicating progress.</li><li><strong>Automatic rerouting:</strong> If the active route starts from the user&#39;s current position, it is automatically recalculated when the user moves more than ~15 meters away from it, or moves to a floor the route doesn&#39;t pass through.</li></ul><h2 id="_4-visual-states" tabindex="-1">4. Visual States <a class="header-anchor" href="#_4-visual-states" aria-label="Permalink to &quot;4. Visual States&quot;">​</a></h2><table><thead><tr><th>Icon</th><th>State</th><th>Meaning</th></tr></thead><tbody><tr><td>Blue circle</td><td>Active</td><td>GPS is on, but compass heading is unavailable.</td></tr><tr><td>Blue arrow</td><td>Directional</td><td>GPS is on and the compass is active (shows the user’s facing direction).</td></tr><tr><td>Hidden dot</td><td>Off-floor</td><td>The user is on a different floor or layer than the one currently displayed.</td></tr><tr><td>Hidden</td><td>No signal</td><td>GPS signal is lost or location permission is denied.</td></tr></tbody></table>',13)]))}const m=e(n,[["render",s]]);export{p as __pageData,m as default};
